#include <SPI.h>
#include <MFRC522.h>

#define SS_PIN  10   // SDA pin on RC522 → Arduino pin 10
#define RST_PIN 9    // RST pin on RC522 → Arduino pin 9

MFRC522 rfid(SS_PIN, RST_PIN);

void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();
  Serial.println("Tap your RFID card...");
}

void loop() {
  // Wait for a card
  if (!rfid.PICC_IsNewCardPresent()) return;
  if (!rfid.PICC_ReadCardSerial())  return;

  // Print UID to Serial Monitor
  Serial.print("Card UID: ");
  for (byte i = 0; i < rfid.uid.size; i++) {
    Serial.print(rfid.uid.uidByte[i], HEX);
    if (i < rfid.uid.size - 1) Serial.print(" ");
  }
  Serial.println();

  rfid.PICC_HaltA();  // Stop reading
}

#include <SPI.h>
#include <MFRC522.h>
#include <Wire.h>
#include <LiquidCrystal_I2C.h>

#define SS_PIN  10
#define RST_PIN 9

MFRC522 rfid(SS_PIN, RST_PIN);
LiquidCrystal_I2C lcd(0x27, 16, 2);  // I2C address 0x27, 16 cols, 2 rows

// ── STUDENT DATABASE ──────────────────────────────
// Replace these UID bytes with your actual card UIDs!
struct Student {
  byte uid[4];
  String name;
};

Student students[] = {
  { {0xA1, 0xB2, 0xC3, 0xD4}, "Jason"   },
  { {0x12, 0x34, 0x56, 0x78}, "Priya"   },
  { {0xDE, 0xAD, 0xBE, 0xEF}, "Arjun"   },
  { {0x11, 0x22, 0x33, 0x44}, "Sneha"   }
};

int studentCount = sizeof(students) / sizeof(students[0]);
// ──────────────────────────────────────────────────

void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();

  lcd.init();
  lcd.backlight();
  lcd.setCursor(0, 0);
  lcd.print(" Attendance "  );
  lcd.setCursor(0, 1);
  lcd.print("  System Ready");
  delay(2000);
  lcd.clear();
  lcd.print("Tap your card!");
}

void loop() {
  if (!rfid.PICC_IsNewCardPresent()) return;
  if (!rfid.PICC_ReadCardSerial())  return;

  // Get tapped card UID
  byte tappedUID[4];
  for (byte i = 0; i < 4; i++) {
    tappedUID[i] = rfid.uid.uidByte[i];
  }

  // Search database for matching UID
  String foundName = "";
  for (int i = 0; i < studentCount; i++) {
    bool match = true;
    for (byte j = 0; j < 4; j++) {
      if (students[i].uid[j] != tappedUID[j]) {
        match = false;
        break;
      }
    }
    if (match) {
      foundName = students[i].name;
      break;
    }
  }

  // Display result on LCD
  lcd.clear();
  if (foundName != "") {
    lcd.setCursor(0, 0);
    lcd.print("Welcome back,");
    lcd.setCursor(0, 1);
    lcd.print(foundName + "!");
    Serial.println("✅ Attendance marked: " + foundName);
  } else {
    lcd.setCursor(0, 0);
    lcd.print("  Access Denied");
    lcd.setCursor(0, 1);
    lcd.print(" Unknown User!");
    Serial.println("❌ Unknown card tapped.");
  }

  delay(3000);       // Show message for 3 seconds
  lcd.clear();
  lcd.print("Tap your card!");
  rfid.PICC_HaltA();
}
